local OIl0OIO0lIl=136
local OIl000O0OOI=117
local OllOIOOIOOl="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function OOIl0lll0l0(d)
    d=(d or ""):gsub("%s+","")
    d=d:gsub("[^"..OllOIOOIOOl.."=]","")
    return (d:gsub(".",function(x)
        if x=="=" then return "" end
        local r,f="",(OllOIOOIOOl:find(x,1,true)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and "1" or "0")
        end
        return r
    end):gsub("%d%d%d?%d?%d?%d?%d?%d?",function(x)
        if #x~=8 then return "" end
        local c=0
        for i=1,8 do
            if x:sub(i,i)=="1" then c=c+2^(8-i) end
        end
        return string.char(c)
    end))
end
local function OIOOOOlIO0O(a,b)
    local r,m=0,1
    while a>0 or b>0 do
        local aa=a%2
        local bb=b%2
        if aa~=bb then r=r+m end
        a=(a-aa)/2
        b=(b-bb)/2
        m=m*2
    end
    return r
end
