    local OOOOO0I000O=(O0lOOOIOlOl-((OIl000O0OOI+OOI0l0IIIIO)%256))%256
    OIlOOlOll0l[OOI0l0IIIIO]=string.char(OIOOOOlIO0O(OOOOO0I000O,OIl0OIO0lIl))
end
local O0OlOIOlOIO=table.concat(OIlOOlOll0l)
